import{_ as i,o as a,c as t,ag as l}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Aliasuri Tmux | Dotfiles (RO)","titleTemplate":":title","description":"Comenzi scurte pentru tmux. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","frontmatter":{"title":"Aliasuri Tmux | Dotfiles","description":"Comenzi scurte pentru tmux. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","lang":"ro-RO","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliasuri Tmux | Previzualizare Dotfiles","canonical":"/ro/aliases/tmux/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliasuri Tmux","pageType":"docs","schemaType":"WebPage","permalink":"/ro/aliases/tmux/"},"headers":[],"relativePath":"ro/aliases/tmux/index.md","filePath":"ro/aliases/tmux/index.md","lastUpdated":1773010926000}'),s={name:"ro/aliases/tmux/index.md"};function o(r,e,n,u,c,d){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="aliasuri-tmux" tabindex="-1">Aliasuri Tmux <a class="header-anchor" href="#aliasuri-tmux" aria-label="Permalink to &quot;Aliasuri Tmux&quot;">​</a></h1><p>Comenzi scurte pentru tmux.</p><p>Această pagină prezintă un grup de aliasuri și scurtăturile sale de comandă obișnuite. Citiți-o mai întâi pentru a înțelege convențiile de denumire, intrările așteptate și tiparele de execuție sigure. Apoi deschideți anexa de referință pentru inventarul complet de comenzi și sintaxa exactă. Aceste aliasuri reduc tastarea repetitivă și mențin un comportament consistent pe macOS, Linux și WSL.</p><h2 id="cand-se-utilizeaza" tabindex="-1">Când se utilizează <a class="header-anchor" href="#cand-se-utilizeaza" aria-label="Permalink to &quot;Când se utilizează&quot;">​</a></h2><p>Utilizați această pagină înainte de lucrul zilnic în shell când aveți nevoie de tipare de comandă previzibile.</p><h2 id="ce-este-inclus" tabindex="-1">Ce este inclus <a class="header-anchor" href="#ce-este-inclus" aria-label="Permalink to &quot;Ce este inclus&quot;">​</a></h2><ul><li>Aliasuri: 11</li><li>Funcții helper: 1</li><li>Fișiere sursă: 1</li></ul><h2 id="exemple-rapide" tabindex="-1">Exemple rapide <a class="header-anchor" href="#exemple-rapide" aria-label="Permalink to &quot;Exemple rapide&quot;">​</a></h2><ul><li><code>tma</code> → <code>&#39;tmux attach-session&#39; # Atașare la ultima sesiune</code></li><li><code>tmat</code> → <code>&#39;tmux attach-session -t&#39; # Atașare la sesiune specifică</code></li><li><code>tmi</code> → <code>&#39;tmux info&#39; # Afișează informații tmux</code></li><li><code>tmka</code> → <code>&#39;tmux kill-server&#39; # Oprește toate sesiunile (server)</code></li><li><code>tmks</code> → <code>&#39;tmux kill-session -a&#39; # Oprește toate sesiunile, exceptând cea curentă</code></li><li><code>tml</code> → <code>&#39;tmux list-sessions&#39; # Listează toate sesiunile</code></li><li><code>tmlp</code> → <code>&#39;tmux list-panes&#39; # Listează panouri</code></li><li><code>tmls</code> → <code>&#39;tmux list-windows&#39; # Listează ferestre</code></li><li><code>tmn</code> → <code>&#39;tmux new-session&#39; # Sesiune nouă fără nume</code></li><li><code>tmr</code> → <code>&#39;tmux source ~/.dotfiles/lib/configurations/tmux/tmux&#39; # Reîncarcă configurarea</code></li><li><code>tms</code> → <code>&#39;tmux new-session -s&#39; # Sesiune nouă cu nume</code></li></ul><h2 id="pasul-urmator" tabindex="-1">Pasul următor <a class="header-anchor" href="#pasul-urmator" aria-label="Permalink to &quot;Pasul următor&quot;">​</a></h2><p>Deschideți lista completă:</p>',11)])])}const x=i(s,[["render",o]]);export{p as __pageData,x as default};
